mapper.select:
SELECT e.id, a.`name`, a.articles_num articlesNum, a.type_id typeId, a.specifications, d.title title, d.odd_number oddNumber, CONVERT(d.create_time, char) createTime, e.apply_use_num applyUseNum FROM asset_articles a, asset_articles_use d, asset_articles_use_goods e
d.create_id = #{createId} AND d.id = e.parent_id AND e.article_id = a.id
${sqlExtract}
AND (a.`name` like '%${keyword}%' OR d.odd_number like '%${keyword}%')
AND a.tenant_id = #{tenantId} AND b.tenant_id = #{tenantId} AND e.tenant_id = #{tenantId}
ORDER BY d.create_time DESC
